81	inline ExecutionManager *getDefaultExecutionManager();
82	
83	/// The ExecutionManager provides a base class describing a concrete sub-system
84	/// for allocating qudits and executing quantum instructions on those qudits.
85	/// This type is templated on the concrete qudit type (`qubit`, `qmode`, etc).
86	/// It exposes an API for getting an available qudit id, returning that id,
87	/// setting and resetting the current execution context, and applying specific
88	/// quantum instructions.
89	class ExecutionManager {
90	protected:
91	  /// Available qudit indices
92	  std::deque<std::size_t> availableIndices;
93	
94	  /// Total qudits available
95	  std::size_t totalQudits;
96	
97	  /// Utility type tracking qudit unique identifiers as they are allocated and
98	  /// deallocated.
99	  QuditIdTracker tracker;
100	
101	  /// Internal - return the next qudit index
102	  std::size_t getNextIndex() { return tracker.getNextIndex(); }
103	
104	  /// Internal - At qudit deallocation, return the qudit index
105	  void returnIndex(std::size_t idx) { tracker.returnIndex(idx); }
106	
107	public:
108	  ExecutionManager() = default;
109	
110	  /// Allocates a qudit and returns its identifier (index).
111	  virtual std::size_t allocateQudit(std::size_t quditLevels = 2) = 0;
112	
113	  /// QuditInfo has been deallocated, return the qudit / id to the pool of
114	  /// qudits.
115	  virtual void returnQudit(const QuditInfo &q) = 0;
116	
117	  /// Checker for qudits that were not deallocated
118	  bool memoryLeaked() { return !tracker.allDeallocated(); }
119	
120	  /// Configure the execution context before an execution.
121	  void configureExecutionContext(const sample_policy &policy);
122	  void configureExecutionContext(const observe_policy &policy);
123	  void configureExecutionContext(ExecutionContext &ctx);
124	
125	  /// Finalize the execution context after an execution.
126	  void finalizeExecutionContext(ExecutionContext &ctx);
127	
128	  virtual void finalizeExecutionContext(const other_policies &policy,
129	                                        ExecutionContext &ctx) {}
130	  virtual sample_result
131	  finalizeExecutionContext(const sample_policy &policy) = 0;
132	
133	  virtual observe_result
134	  finalizeExecutionContext(const observe_policy &policy) = 0;
135	
136	  /// Set up the execution manager for a new execution.
137	  virtual void beginExecution() {}
138	
139	  /// Clean up the execution manager after an execution.
140	  virtual void endExecution() {}
141	
142	  /// @brief Initialize the state of the given qudits to the provided
143	  /// state vector.
144	  virtual void initializeState(const std::vector<QuditInfo> &targets,
145	                               const void *state,
146	                               simulation_precision precision) = 0;
147	  /// @brief Initialize the state of the given qudits to the provided
148	  /// simulation state.
149	  virtual void initializeState(const std::vector<QuditInfo> &targets,
150	                               const SimulationState *state) = 0;
151	
152	  /// @brief Initialize the state of the given qudits to the provided
153	  /// simulation state.
154	  virtual void initializeState(const std::vector<QuditInfo> &targets,
155	                               const SimulationState &state) {
156	    initializeState(targets, &state);
157	  }
158	
159	  /// Apply the quantum instruction with the given name, on the provided target
160	  /// qudits. Supports input of control qudits and rotational parameters. Can
161	  /// also optionally take a spin_op as input to affect a general Pauli
162	  /// rotation.
163	  virtual void apply(const std::string_view gateName,
164	                     const std::vector<double> &params,
165	                     const std::vector<QuditInfo> &controls,
166	                     const std::vector<QuditInfo> &targets,
167	                     bool isAdjoint = false,
168	                     const spin_op_term op = cudaq::spin_op::identity()) = 0;
169	
170	  /// @brief Apply a fine-grain noise operation within a kernel.
171	  virtual void applyNoise(const kraus_channel &channelName,
172	                          const std::vector<QuditInfo> &targets) = 0;
173	
174	  /// Reset the qubit to the |0> state
175	  virtual void reset(const QuditInfo &target) = 0;
176	
177	  /// Begin an region of code where all operations will be adjoint-ed
178	  virtual void startAdjointRegion() = 0;
179	  /// End the adjoint region
180	  virtual void endAdjointRegion() = 0;
181	
182	  /// Start a region of code where all operations will be controlled on the
183	  /// given qudits.
184	  virtual void
185	  startCtrlRegion(const std::vector<std::size_t> &control_qubits) = 0;
186	  /// End the control region
187	  virtual void endCtrlRegion(std::size_t n_controls) = 0;
188	
189	  // Measure the qudit and return the observed state \f$(0,1,2,3,...)\f$; e.g.,
190	  // for qubits this can return 0 or 1.
191	  virtual int measure(const QuditInfo &target,
192	                      const std::string registerName = "") = 0;
193	
194	  /// Measure the current state in the respective basis given by each term in
195	  /// the spin op, return the expectation value <term>.
196	  virtual SpinMeasureResult measure(const cudaq::spin_op &op) = 0;
197	
198	  /// Synchronize - run all queue-ed instructions
199	  virtual void synchronize() = 0;
200	
201	  /// Flush the gate queue (needed for accurate timing information)
202	  virtual void flushGateQueue() {};
203	
204	  /// @brief Register a new custom unitary operation under the
205	  /// provided operation name.
206	  template <typename T>
207	  void registerOperation(const std::string &name) {
208	    customOpRegistry::getInstance().registerOperation<T>(name);
209	  }
210	
211	  /// Clear the registered operations
212	  virtual void clearRegisteredOperations() {
213	    customOpRegistry::getInstance().clearRegisteredOperations();
214	  }
215	
216	  virtual ~ExecutionManager() = default;
217	
218	  /// @brief Execute the given function within the given execution context.
219	  template <typename Policy>
220	  static auto with_default_em(Policy &policy, std::function<void()> f)
221	      -> Policy::result_type {
222	    auto em = getDefaultExecutionManager();
223	    em->configureExecutionContext(policy);
224	    em->beginExecution();
225	    typename Policy::result_type result;
226	    detail::try_finally([&] { f(); },
227	                        [&] {
228	                          result = em->finalizeExecutionContext(policy);
229	                          em->endExecution();
230	                        });
231	    return result;
232	  }
233	};
