253	ExecutionManager *getRegisteredExecutionManager();
254	
255	// Function declarations for explicit execution manager override
256	// (implemented in execution_manager.cpp)
257	ExecutionManager *getExecutionManagerInternal();
258	void setExecutionManagerInternal(ExecutionManager *em);
259	void resetExecutionManagerInternal();
