261	/// @brief Get an instance of the default execution manager.
262	///
263	/// Returns the explicitly set manager if one was set via
264	/// setExecutionManagerInternal(), otherwise returns the default registered
265	/// manager via getRegisteredExecutionManager().
266	inline ExecutionManager *getDefaultExecutionManager() {
267	  ExecutionManager *em = getExecutionManagerInternal();
268	  if (em)
269	    return em;
270	  return getRegisteredExecutionManager();
271	}
272	
273	namespace detail {
274	ExecutionManager *getExecutionManagerFromContext();
275	}
276	
277	/// Get the current execution manager.
278	///
279	/// This may only be called within a CUDA-Q kernel execution.
280	inline ExecutionManager *getExecutionManager() {
281	  ExecutionManager *em = detail::getExecutionManagerFromContext();
282	  if (em) {
283	    return em;
284	  }
285	  // if not execution context is set, use the default execution manager
286	  return getDefaultExecutionManager();
287	}
288	
289	} // namespace cudaq
