291	// The following macro is to be used by ExecutionManager subclass developers. It
292	// will define the global thread_local execution manager pointer instance, and
293	// define the factory function for clients to get reference to the execution
294	// manager.
295	#define CONCAT(a, b) CONCAT_INNER(a, b)
296	#define CONCAT_INNER(a, b) a##b
297	#define CUDAQ_REGISTER_EXECUTION_MANAGER(Manager, Name)                        \
298	  namespace cudaq {                                                            \
299	  ExecutionManager *getRegisteredExecutionManager() {                          \
300	    thread_local static std::unique_ptr<ExecutionManager> qis_manager =        \
301	        std::make_unique<Manager>();                                           \
302	    return qis_manager.get();                                                  \
303	  }                                                                            \
304	  }                                                                            \
305	  extern "C" {                                                                 \
306	  cudaq::ExecutionManager *CONCAT(getRegisteredExecutionManager_, Name)() {    \
307	    thread_local static std::unique_ptr<cudaq::ExecutionManager> qis_manager = \
308	        std::make_unique<cudaq::Manager>();                                    \
309	    return qis_manager.get();                                                  \
310	  }                                                                            \
311	  }
