337	cudaq::KernelThunkResultType
338	cudaq::altLaunchKernel(const char *kernelName,
339	                       cudaq::KernelThunkType kernelFunc, void *kernelArgs,
340	                       std::uint64_t argsSize, std::uint64_t resultOffset) {
341	  ScopedTraceWithContext("altLaunchKernel", kernelName, argsSize);
342	  auto &platform = *getQuantumPlatformInternal();
343	  std::string kernName = kernelName;
344	  KernelArgs args{KernelArgs::PackedArgs{kernelArgs, argsSize, resultOffset}};
345	  SourceModule src{kernName, kernelFunc};
346	  auto ctx = cudaq::getExecutionContext();
347	  if (ctx && ctx->executeKernelApi) {
348	    ctx->executeKernelApi(src, args);
349	    return {};
350	  }
351	  std::size_t qpu_id = cudaq::getCurrentQpuId();
352	  return platform.unifiedLaunchModule(src, args, qpu_id);
353	}
