355	cudaq::KernelThunkResultType
356	cudaq::streamlinedLaunchKernel(const char *kernelName,
357	                               const std::vector<void *> &rawArgs) {
358	  std::size_t argsSize = rawArgs.size();
359	  ScopedTraceWithContext("streamlinedLaunchKernel", kernelName, argsSize);
360	  std::string kernName = kernelName;
361	  KernelArgs args{rawArgs};
362	  SourceModule src{kernName};
363	  auto ctx = cudaq::getExecutionContext();
364	  if (ctx && ctx->executeKernelApi) {
365	    ctx->executeKernelApi(src, args);
366	    return {};
367	  }
368	  auto &platform = *getQuantumPlatformInternal();
369	  std::size_t qpu_id = cudaq::getCurrentQpuId();
370	  [[maybe_unused]] auto r = platform.unifiedLaunchModule(src, args, qpu_id);
371	  // NB: The streamlined launch will never return results. Use alt or hybrid if
372	  // the kernel returns results.
373	  return {};
374	}
