376	cudaq::KernelThunkResultType
377	cudaq::streamlinedLaunchModule(const CompiledModule &compiled,
378	                               const std::vector<void *> &rawArgs) {
379	  ScopedTraceWithContext("streamlinedLaunchModule", compiled.getName(),
380	                         rawArgs.size());
381	
382	  auto ctx = cudaq::getExecutionContext();
383	  if (ctx && ctx->executeKernelApi) {
384	    ctx->executeKernelApi(compiled, {rawArgs});
385	    return {};
386	  }
387	  auto &platform = *getQuantumPlatformInternal();
388	  std::size_t qpu_id = getCurrentQpuId();
389	  return platform.unifiedLaunchModule(compiled, {rawArgs}, qpu_id);
390	}
