392	cudaq::KernelThunkResultType
393	cudaq::hybridLaunchKernel(const char *kernelName, cudaq::KernelThunkType kernel,
394	                          void *args, std::uint64_t argsSize,
395	                          std::uint64_t resultOffset,
396	                          const std::vector<void *> &rawArgs) {
397	  ScopedTraceWithContext("hybridLaunchKernel", kernelName);
398	  auto &platform = *getQuantumPlatformInternal();
399	  const std::string kernName = kernelName;
400	  std::size_t qpu_id = cudaq::getCurrentQpuId();
401	  SourceModule src{kernName, kernel};
402	
403	  KernelArgs kargs = platform.is_remote(qpu_id)
404	                         ? KernelArgs{rawArgs}
405	                         : KernelArgs{{args, argsSize, resultOffset}, rawArgs};
406	
407	  auto ctx = cudaq::getExecutionContext();
408	  if (ctx && ctx->executeKernelApi) {
409	    ctx->executeKernelApi(src, kargs);
410	    return {};
411	  }
412	
413	  if (platform.is_remote(qpu_id)) {
414	    // This path should never call a kernel that returns results.
415	    [[maybe_unused]] auto r = platform.unifiedLaunchModule(src, kargs, qpu_id);
416	    return {};
417	  }
418	  return platform.unifiedLaunchModule(src, kargs, qpu_id);
419	}
