26	/// @brief Check whether a kernel uses conditional feedback (measurement-
27	/// dependent branching). Checks MLIR metadata first, then optionally checks
28	/// the ExecutionContext's registerNames (populated during library-mode
29	/// tracing).
30	///
31	/// @param kernelName Name of the kernel (for MLIR registry lookup)
32	/// @param ctx Optional pointer to an ExecutionContext populated after tracing
33	/// @return true if conditional feedback is detected
34	inline bool hasConditionalFeedback(const std::string &kernelName,
35	                                   const ExecutionContext *ctx = nullptr) {
36	  if (cudaq::kernelHasConditionalFeedback(kernelName))
37	    return true;
38	  if (ctx && !ctx->registerNames.empty())
39	    return true;
40	  return false;
41	}
42	} // namespace detail
43	
44	/// @brief Define a combined sample function validation concept.
45	/// These concepts provide much better error messages than old-school SFINAE
46	template <typename QuantumKernel, typename... Args>
47	concept SampleCallValid =
48	    ValidArgumentsPassed<QuantumKernel, Args...> &&
49	    HasVoidReturnType<std::invoke_result_t<QuantumKernel, Args...>>;
50	
51	namespace detail {
52	
53	/// @brief Validate sampling arguments, populate the given execution context
54	/// and sample policy, and (in library mode) trace the kernel to detect any
55	/// mid-circuit conditional feedback.
56	/// @param ctx The execution context to populate (must already be constructed
57	/// with name "sample").
58	/// @param policy The sample policy to populate.
59	template <typename KernelFunctor>
60	void samplePreamble(ExecutionContext &ctx, sample_policy &policy,
61	                    KernelFunctor &&wrappedKernel, quantum_platform &platform,
62	                    const std::string &kernelName, int shots,
63	                    bool explicitMeasurements, std::size_t qpu_id,
64	                    std::size_t batchIteration = 0,
65	                    std::size_t totalBatchIters = 0) {
66	  if (cudaq::detail::hasConditionalFeedback(kernelName))
67	    throw std::runtime_error(
68	        "`cudaq::sample` and `cudaq::sample_async` no longer support kernels "
69	        "that branch on measurement results. Kernel '" +
70	        kernelName +
71	        "' uses conditional feedback. Use `cudaq::run` or `cudaq::run_async` "
72	        "instead. See CUDA-Q documentation for migration guide.");
73	
74	  if (explicitMeasurements && !platform.supports_explicit_measurements())
75	    throw std::runtime_error("The sampling option `explicit_measurements` is "
76	                             "not supported on this target.");
77	
78	  ctx.kernelName = kernelName;
79	  ctx.batchIteration = batchIteration;
80	  ctx.totalIterations = totalBatchIters;
81	  ctx.explicitMeasurements = explicitMeasurements;
82	
83	  policy.kernelName = kernelName;
84	  policy.options.shots = shots;
85	  policy.options.explicit_measurements = explicitMeasurements;
86	  policy.noiseModel = platform.get_noise(qpu_id);
87	
88	  // For now the noise model has to be duplicated on the policy unfortunately.
89	  // get_noise() still expects it on the execution context.
90	  // TODO: Store the noise on the platform or QPU instead.
91	  ctx.noiseModel = policy.noiseModel;
92	
93	#ifdef CUDAQ_LIBRARY_MODE
94	  // If we have a kernel that has its quake code registered, we
95	  // won't check for if statements with the tracer.
96	  auto isRegistered = detail::isKernelGenerated(kernelName);
97	
98	  // One extra check to see if we have mid-circuit
99	  // measures in library mode
100	  if (!isRegistered && !ctx.hasConditionalsOnMeasureResults) {
101	    // Trace the kernel function
102	    ExecutionContext context("tracer");
103	    context.qpuId = qpu_id;
104	    auto &platform = get_platform();
105	    platform.with_execution_context(context,
106	                                    std::forward<KernelFunctor>(wrappedKernel));
107	    // In trace mode, if we have a measure result
108	    // that is passed to an if statement, then
109	    // we'll have collected registernames
110	    if (!context.registerNames.empty()) {
111	      // append new register names to the main sample context
112	      for (std::size_t i = 0; i < context.registerNames.size(); ++i)
113	        ctx.registerNames.emplace_back("auto_register_" + std::to_string(i));
114	
115	      ctx.hasConditionalsOnMeasureResults = true;
116	    }
117	  }
118	#endif
119	}
