281	  // Need the code to be lowered to llvm and the kernel to be registered
282	  // so that we can check for conditional feedback / mid circ measurement
283	  if constexpr (has_name<QuantumKernel>::value) {
284	    static_cast<cudaq::detail::kernel_builder_base &>(kernel).jitCode();
