289	  auto kernelName = cudaq::getKernelName(kernel);
290	  return detail::runSampling(
291	      [&]() mutable { kernel(std::forward<Args>(args)...); }, platform,
292	      kernelName, /*shots=*/DEFAULT_NUM_SHOTS,
293	      /*explicitMeasurements=*/false);
294	}
