498	/// @brief Run the standard sample functionality over a set of N
499	/// argument packs. For a kernel with signature `void(Args...)`, this
500	/// function takes as input a set of `vector<Arg>...`, a vector for
501	/// each argument type in the kernel signature. The vectors must be of
502	/// equal length, and element `i` of each vector is used in
503	/// execution `i` of the standard sample function. Results are collected
504	/// from the execution of every argument set and returned.
505	template <typename QuantumKernel, typename... Args>
506	  requires SampleCallValid<QuantumKernel, Args...>
507	std::vector<sample_result> sample(QuantumKernel &&kernel,
508	                                  ArgumentSet<Args...> &&params) {
509	  // Get the platform and query the number of qpus
510	  auto &platform = cudaq::get_platform();
511	  auto numQpus = platform.num_qpus();
512	
513	  // Create the functor that will broadcast the sampling tasks across
514	  // all requested argument sets provided.
515	  detail::BroadcastFunctorType<sample_result, Args...> functor =
516	      [&](std::size_t qpuId, std::size_t counter, std::size_t N,
517	          Args &...singleIterParameters) -> sample_result {
518	    auto kernelName = cudaq::getKernelName(kernel);
519	    auto ret = detail::runSampling(
520	        [&kernel, &singleIterParameters...]() mutable {
521	          kernel(std::forward<Args>(singleIterParameters)...);
522	        },
523	        platform, kernelName, /*shots=*/DEFAULT_NUM_SHOTS,
524	        /*explicitMeasurements=*/false, qpuId, counter, N);
525	    return ret;
526	  };
527	
528	  // Broadcast the executions and return the results.
529	  return detail::broadcastFunctionOverArguments<sample_result, Args...>(
530	      numQpus, platform, functor, params);
531	}
