638	        platform, kernelName, /*shots=*/DEFAULT_NUM_SHOTS,
639	        /*explicitMeasurements=*/false, qpuId, counter, N);
640	    return ret;
641	  };
642	
643	  // Broadcast the executions and return the results.
644	  return detail::broadcastFunctionOverArguments<sample_result, Args...>(
645	      numQpus, platform, functor, params);
646	}
647	
648	/// @brief Run the standard sample functionality over a set of N
649	/// argument packs. For a kernel with signature `void(Args...)`, this
650	/// function takes as input a set of `vector<Arg>...`, a vector for
651	/// each argument type in the kernel signature. The vectors must be of
652	/// equal length, and the element `i` of each vector is used in
653	/// execution `i` of the standard sample function. Results are collected
654	/// from the execution of every argument set and returned. This overload
655	/// allows the number of circuit executions (shots) to be specified.
656	template <typename QuantumKernel, typename... Args>
657	  requires SampleCallValid<QuantumKernel, Args...>
658	[[deprecated("Use sample() overload instead")]] std::vector<sample_result>
659	sample_n(std::size_t shots, QuantumKernel &&kernel,
660	         ArgumentSet<Args...> &&params) {
661	  // Get the platform and query the number of qpus
662	  auto &platform = cudaq::get_platform();
663	  auto numQpus = platform.num_qpus();
664	
665	  // Create the functor that will broadcast the sampling tasks across
666	  // all requested argument sets provided.
667	  detail::BroadcastFunctorType<sample_result, Args...> functor =
668	      [&](std::size_t qpuId, std::size_t counter, std::size_t N,
669	          Args &...singleIterParameters) -> sample_result {
670	    auto kernelName = cudaq::getKernelName(kernel);
671	    auto ret = detail::runSampling(
672	        [&kernel, &singleIterParameters...]() mutable {
673	          kernel(std::forward<Args>(singleIterParameters)...);
674	        },
675	        platform, kernelName, shots, /*explicitMeasurements=*/false, qpuId,
676	        counter, N);
677	    return ret;
678	  };
679	
680	  // Broadcast the executions and return the results.
681	  return detail::broadcastFunctionOverArguments<sample_result, Args...>(
682	      numQpus, platform, functor, params);
683	}
